var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마침 한 권을 다 읽은 참이었습니다. 늦으셨군요.","JPN":"ちょうど一冊読み終えたところです。遅かったのですね。","ENG":"I have just finished reading an entire book. You are late.","TWN":"遲到囉，我都讀完一本書了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야, 꼰대. 네가 왜 여기 있어?","JPN":"なんだよ、ばばあ。なんであんたがここにいるわけ？","ENG":"Huh? Snob? What are you doing here?","TWN":"搞什麼，四眼姊姊，你怎麼會在這裡？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님. 루체 자매님께 말버릇이 그게 뭐예요?","JPN":"シスター・ルーパー。シスター・ルーチェになんて口の利き方ですか。","ENG":"Sister Looper, you shouldn't talk to Sister Luce like that.","TWN":"洛珀姊妹，怎麼可以這樣對露契姊妹說話呢？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"여전히 무례하군요. 시스터 루퍼.","JPN":"相変わらず無礼ですね。シスタールーパー。","ENG":"Still rude as ever I see, Sister Looper.","TWN":"你還是一樣沒大沒小的呢，洛珀姊妹。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 저는 시스터 넬슨처럼 무른 성격이 아닙니다.","JPN":"ですが、私はシスターネルソンのように甘い性格ではありません。","ENG":"However, I will am not as gentle as Sister Nelson.","TWN":"不過我可不像尼爾森姊妹那麼溫柔。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 밑에서 일하시는 동안, 기꺼이 조신한 시스터로 만들어드리죠.","JPN":"私の下で働く間、慎み深いシスターになるよう、喜んで再教育いたしましょう。","ENG":"While you are working for me, I will gladly train you to become a well-behaved Sister.","TWN":"你在我底下做事的這段時間，我很樂意把你打造成一個端莊的姊妹。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"미사 때 포도주 대신 보드카라도 마셨나? 누가 누구 밑에서 일해?","JPN":"ミサでブドウ酒の代わりにウォッカでも飲んだ？　誰が誰の下で働くって？","ENG":"Who switched out your wine for vodka during Mass? Who's working under who now?","TWN":"彌撒的時候你喝的不是葡萄酒，而是伏特加是不是？誰要在你底下做事？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님, 그 말씀은?","JPN":"シスター・ルーチェ、それはつまり？","ENG":"Sister Luce, what you mean is...?","TWN":"露契姊妹，那是什麼意思呢？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 서거하시고 행정처리는 아직입니다만.","JPN":"猊下が逝去なさって、行政的な処理はまだ行われておりませんが。","ENG":"His Eminence has passed away, but the administrative process is still pending.","TWN":"主教安息後，雖然還有些行政流程要走，"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"금일부로 제 9호 기적심의회의 집행 사제로 배속되었습니다.","JPN":"今日をもって第9号奇跡審議会の執行司祭として配属されました。","ENG":"Effective immediately, I have been assigned as the Inquisitorial Priest of Miracle Investigation Council 9.","TWN":"但從今天起，我將接任第9奇蹟議會執行祭司一職。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"피차 익숙한 얼굴들이니 인사치레는 생략하죠.","JPN":"お互い知った顔ぶれですから、挨拶は省きましょう。","ENG":"I shall skip the introductions as we are already acquainted.","TWN":"既然大家都已經見過面，自我介紹的部分就先省略吧。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리 대신 꼰대 안경이라고? 환장하겠네.","JPN":"のっぽの代わりに眼鏡ばばあ？　あり得ない。","ENG":"Sheesh...! First Long Legs, and now it's Specky Snob?","TWN":"四眼姊姊要取代高個子？合理嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"집행 사제라고 하시면 설마…….","JPN":"執行司祭とおっしゃいますと、まさか……","ENG":"If you're the Inquisitorial Priest, then...","TWN":"你說執行祭司……"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 지시입니다.","JPN":"聖皇庁の指示です。","ENG":"It is an order from the Holy Curia.","TWN":"是聖皇廳下的令。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"현 시간부로, 우리 제 9호 기적심의회는 요한 추기경을 살해한 베네딕트 콘스탄틴을 추격하게 되었습니다.","JPN":"現時点をもって、第9号奇跡審議会はヨハン枢機卿を殺したベネディクト・コンスタンティンを追撃することになりました。","ENG":"As of this time, Miracle Investigation Council 9 will begin its investigation into Cardinal Johan's murderer, Benedict Constantine.","TWN":"即刻起，我們第9奇蹟議會將捉拿殺害約翰樞機主教的犯人，本尼迪克特·康斯坦丁。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"변절자의 목적을 읽어내는 것과 그 죗값을 치르게 하는 것. 그것이 우리의 목표죠.","JPN":"宗旨替えの目的を読むこととその罪を償わせること。それが私たちの目標です。","ENG":"Read the traitor's objectives and make him pay for his sins. That will be our goal.","TWN":"我們的目標是，讀出叛徒的目的，以及讓他付出應有的代價。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……아니요. 루체 자매님.","JPN":"……いいえ。シスター・ルーチェ。","ENG":"No, Sister Luce.","TWN":"……不，露契姊妹。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}}]`);export{e as default};